+        let cx = Cx::for_request();
+        let tx = {
+            let mut guard = self.inner.lock().unwrap();
+            guard.pending_ui.remove(&response.id)
+        };
+        tx.is_some_and(|sender| sender.send(&cx, response).is_ok())
+    }
