+
+pub struct MockHttpServer {
+    addr: SocketAddr,
+    routes: Arc<Mutex<std::collections::HashMap<RouteKey, MockHttpResponse>>>,
+    requests: Arc<Mutex<Vec<MockHttpRequest>>>,
