+fn normalize_strings_in_value(value: &mut Value, cwd: &Path) {
+    match value {
+        Value::Null | Value::Bool(_) | Value::Number(_) => {}
+        Value::String(s) => {
+            *s = normalize_string(s, cwd);
+        }
+        Value::Array(items) => {
+            for item in items {
+                normalize_strings_in_value(item, cwd);
+            }
+        }
+        Value::Object(map) => {
+            for (_key, item) in map.iter_mut() {
