+    // 2) Normalize absolute paths under cwd to "<cwd>/...".
+    let cwd = cwd.display().to_string();
+    let cwd_backslashes = cwd.replace('/', "\\");
+    let mut out = without_ansi.to_string();
+    if !cwd.is_empty() {
+        out = out.replace(&cwd, "<cwd>");
+        out = out.replace(&cwd_backslashes, "<cwd>");
+    }
