+fn preferred_correlation_id<'a>(
+    corr: &'a serde_json::Map<String, Value>,
+    key: &'static str,
+    kind: &'static str,
+) -> Option<(&'static str, &'a str)> {
+    let id = corr.get(key).and_then(Value::as_str)?;
+    let id = id.trim();
+    if id.is_empty() {
+        return None;
+    }
+    Some((kind, id))
