+			const result = ms(params.duration as ms.StringValue);
+			if (result === undefined) {
+				return {
+					content: [{ type: "text", text: `Invalid duration: "${params.duration}"` }],
+					isError: true,
+					details: {},
+				};
+			}
+			return {
+				content: [{ type: "text", text: `${params.duration} = ${result} milliseconds` }],
+				details: {},
+			};
+		},
+	});
