+    async fn stream(
+        &self,
+        _context: &Context,
+        _options: &StreamOptions,
+    ) -> pi::error::Result<
+        Pin<Box<dyn futures::Stream<Item = pi::error::Result<StreamEvent>> + Send>>,
+    > {
+        Ok(Box::pin(stream::empty()))
+    }
+}
+
+fn dummy_model_entry() -> ModelEntry {
+    let model = Model {
+        id: "dummy-model".to_string(),
+        name: "Dummy Model".to_string(),
+        api: "dummy-api".to_string(),
+        provider: "dummy".to_string(),
+        base_url: "https://example.invalid".to_string(),
+        reasoning: false,
+        input: vec![InputType::Text],
+        cost: ModelCost {
+            input: 0.0,
+            output: 0.0,
+            cache_read: 0.0,
+            cache_write: 0.0,
+        },
+        context_window: 4096,
+        max_tokens: 1024,
+        headers: HashMap::new(),
+    };
+
+    ModelEntry {
+        model,
+        api_key: None,
+        headers: HashMap::new(),
+        auth_header: false,
+        compat: None,
+    }
+}
+
+fn build_app(harness: &TestHarness) -> PiApp {
+    let config = Config::default();
+    let cwd = harness.temp_dir().to_path_buf();
+    let tools = ToolRegistry::new(&[], &cwd, Some(&config));
+    let provider: Arc<dyn Provider> = Arc::new(DummyProvider);
+    let agent = Agent::new(provider, tools, AgentConfig::default());
+    let session = Session::in_memory();
+    let resources = ResourceLoader::empty(config.enable_skill_commands());
+    let resource_cli = ResourceCliOptions {
+        no_skills: false,
+        no_prompt_templates: false,
+        no_extensions: false,
+        no_themes: false,
+        skill_paths: Vec::new(),
+        prompt_paths: Vec::new(),
+        extension_paths: Vec::new(),
+        theme_paths: Vec::new(),
+    };
+    let model_entry = dummy_model_entry();
+    let model_scope = vec![model_entry.clone()];
+    let available_models = vec![model_entry.clone()];
+    let (event_tx, _event_rx) = mpsc::channel(1024);
+
+    let mut app = PiApp::new(
+        agent,
+        session,
+        config,
+        resources,
+        resource_cli,
+        cwd,
+        model_entry,
+        model_scope,
+        available_models,
+        Vec::new(),
+        event_tx,
+        test_runtime_handle(),
+        true,
+        None,
+    );
